class Solution:
    def maximumLength(self, nums, k):
        n = len(nums)
        dp = [[1] * (k + 1) for _ in range(n)]
        for i in range(n):
            for p in range(i):
                for j in range(k + 1):
                    if nums[p] == nums[i]:
                        if dp[p][j] + 1 > dp[i][j]:
                            dp[i][j] = dp[p][j] + 1
                    elif j > 0:
                        if dp[p][j-1] + 1 > dp[i][j]:
                            dp[i][j] = dp[p][j-1] + 1
        return max(dp[i][j] for i in range(n) for j in range(k + 1))

