class Solution:
    def maximumLength(self, nums, k):
        from collections import defaultdict
        n = len(nums)
        # best_same[j][v] = max dp[p][j] where nums[p] == v
        best_same = [defaultdict(int) for _ in range(k + 1)]
        # top2_diff[j] = list of (dp_val, num_val) top-2 by dp_val for all prev positions
        top2 = [[] for _ in range(k + 1)]  # each entry: (val, nums_val)
        ans = 1

        def update_top2(lst, val, num):
            if not lst:
                lst.append((val, num))
            elif len(lst) == 1:
                if val >= lst[0][0]:
                    lst.insert(0, (val, num))
                else:
                    lst.append((val, num))
            else:
                if val >= lst[0][0]:
                    lst[1] = lst[0]
                    lst[0] = (val, num)
                elif val > lst[1][0]:
                    lst[1] = (val, num)

        def best_diff(lst, num):
            for val, nv in lst:
                if nv != num:
                    return val
            return 0

        for i in range(n):
            v = nums[i]
            new_dp = [1] * (k + 1)
            for j in range(k + 1):
                # same value extension
                same_ext = best_same[j][v] + 1
                if same_ext > new_dp[j]:
                    new_dp[j] = same_ext
                # different value extension
                if j > 0:
                    diff_ext = best_diff(top2[j-1], v) + 1
                    if diff_ext > new_dp[j]:
                        new_dp[j] = diff_ext
            for j in range(k + 1):
                if new_dp[j] > ans:
                    ans = new_dp[j]
                if new_dp[j] > best_same[j][v]:
                    best_same[j][v] = new_dp[j]
                update_top2(top2[j], new_dp[j], v)
        return ans

