var maximumLength = function(nums, k) {
    const n = nums.length;
    const bestSame = Array.from({length: k+1}, () => new Map());
    // top2[j] = [{val, num}, ...] at most 2
    const top2 = Array.from({length: k+1}, () => []);

    function updateTop2(lst, val, num) {
        if (lst.length === 0) { lst.push({val, num}); return; }
        if (lst.length === 1) {
            if (val >= lst[0].val) lst.unshift({val, num});
            else lst.push({val, num});
            return;
        }
        if (val >= lst[0].val) { lst[1] = lst[0]; lst[0] = {val, num}; }
        else if (val > lst[1].val) lst[1] = {val, num};
    }
    function bestDiff(lst, num) {
        for (const e of lst) if (e.num !== num) return e.val;
        return 0;
    }

    let ans = 1;
    for (let i = 0; i < n; i++) {
        const v = nums[i];
        const newDp = new Array(k+1).fill(1);
        for (let j = 0; j <= k; j++) {
            const sameExt = (bestSame[j].get(v) || 0) + 1;
            if (sameExt > newDp[j]) newDp[j] = sameExt;
            if (j > 0) {
                const diffExt = bestDiff(top2[j-1], v) + 1;
                if (diffExt > newDp[j]) newDp[j] = diffExt;
            }
        }
        for (let j = 0; j <= k; j++) {
            if (newDp[j] > ans) ans = newDp[j];
            if (newDp[j] > (bestSame[j].get(v) || 0)) bestSame[j].set(v, newDp[j]);
            updateTop2(top2[j], newDp[j], v);
        }
    }
    return ans;
};
